# .github/workflows/performance.yml
name: Performance Budget Check

on: [push, pull_request]

jobs:
  bundle-size:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4
      - uses: oven-sh/setup-bun@v1

      - name: Install dependencies
        run: bun install

      - name: Build
        run: bun run build

      - name: Check bundle sizes
        run: |
          # Main bundle should be under 200KB gzipped
          MAIN_SIZE=$(gzip -c dist/assets/index-*.js | wc -c)
          if [ $MAIN_SIZE -gt 204800 ]; then
            echo "Main bundle too large: ${MAIN_SIZE} bytes (max: 200KB)"
            exit 1
          fi

          # Total JS should be under 500KB gzipped
          TOTAL_SIZE=$(gzip -c dist/assets/*.js | wc -c)
          if [ $TOTAL_SIZE -gt 512000 ]; then
            echo "Total JS too large: ${TOTAL_SIZE} bytes (max: 500KB)"
            exit 1
          fi

      - name: Lighthouse CI
        uses: treosh/lighthouse-ci-action@v10
        with:
          configPath: ./lighthouserc.json
