+
+  /**
+   * Clean up resources
+   */
+  dispose(): void {
+    this.stop();
+    this.queue = [];
+    this.messageHandler = undefined;
+    this.onStateChange = undefined;
+    this.onPause = undefined;
+    this.onResume = undefined;
+  }
